// ============================================================
// WF01 — Parse Airbnb email (v2 — adapte au format reel)
// IMPORTANT: utilise textHtml (pas html) pour IMAP v2
// ============================================================

const html = $input.item.json.textHtml || $input.item.json.html || "";
const subject = $input.item.json.subject || "";
const messageId = $input.item.json.messageId || "";

// --- Detection du type d'email ---
let emailType = "unknown"; // v2: default unknown (pas confirmation) pour eviter faux positifs

if (/annul/i.test(subject) || /cancel/i.test(subject)) {
  emailType = "cancellation";
} else if (/modifi/i.test(subject) || /updated/i.test(subject) || /changed/i.test(subject)) {
  emailType = "modification";
} else if (/r[e\u00e9]serv/i.test(subject) || /confirm/i.test(subject) || /en attente/i.test(subject) || /demande de r/i.test(subject)) {
  emailType = "confirmation";
} else if (/renseignement/i.test(subject) || /inquiry/i.test(subject) || /question/i.test(subject)) {
  emailType = "inquiry";
}

// --- Extraction du nom du voyageur ---
let guestName = "";

// Pattern 1: "demande de Alexis" ou "demande de Jean Dupont"
let m = subject.match(/demande de ([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);
if (m) guestName = m[1].trim();

// Pattern 2: dans le HTML "demande de Alexis"
if (!guestName) {
  m = html.match(/demande de ([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);
  if (m) guestName = m[1].trim();
}

// Pattern 3: "a reserve" ou "a reserve"
if (!guestName) {
  m = html.match(/([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)\s+a\s+r[e\u00e9]serv/);
  if (m) guestName = m[1].trim();
}

// Pattern 4: aria-label avec un prenom
if (!guestName) {
  m = html.match(/aria-label="([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)"/);
  if (m) guestName = m[1].trim();
}

// Pattern 5: "Votre voyageur : Xxx"
if (!guestName) {
  m = html.match(/voyageur\s*:\s*([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/i);
  if (m) guestName = m[1].trim();
}

// --- Extraction des dates ---
const moisFR = {
  "janv": "01", "janvier": "01", "jan": "01",
  "fevr": "02", "f\u00e9vr": "02", "fevrier": "02", "f\u00e9vrier": "02", "fev": "02", "feb": "02",
  "mars": "03", "mar": "03",
  "avr": "04", "avril": "04", "apr": "04",
  "mai": "05", "may": "05",
  "juin": "06", "jun": "06",
  "juil": "07", "juillet": "07", "jul": "07",
  "aout": "08", "ao\u00fbt": "08", "aug": "08",
  "sept": "09", "septembre": "09", "sep": "09",
  "oct": "10", "octobre": "10",
  "nov": "11", "novembre": "11",
  "dec": "12", "d\u00e9c": "12", "decembre": "12", "d\u00e9cembre": "12"
};

function getMonth(str) {
  const key = str.toLowerCase().replace(/\./g, "");
  return moisFR[key] || null;
}

let checkIn = "";
let checkOut = "";

// Pattern 1: format compact "19-20 fevr. 2026" (jour-jour mois annee)
m = subject.match(/(\d{1,2})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
if (!m) m = html.match(/(\d{1,2})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
if (m) {
  const month = getMonth(m[3]);
  if (month) {
    checkIn = m[4] + "-" + month + "-" + m[1].padStart(2, "0");
    checkOut = m[4] + "-" + month + "-" + m[2].padStart(2, "0");
  }
}

// Pattern 2: format complet "19 fevr. 2026 - 20 fevr. 2026"
if (!checkIn) {
  m = (subject + " " + html).match(/(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  if (m) {
    const m1 = getMonth(m[2]);
    const m2 = getMonth(m[5]);
    if (m1) checkIn = m[3] + "-" + m1 + "-" + m[1].padStart(2, "0");
    if (m2) checkOut = m[6] + "-" + m2 + "-" + m[4].padStart(2, "0");
  }
}

// Pattern 3: "Arrivee" et "Depart" dans le HTML
if (!checkIn) {
  const arrM = html.match(/[Aa]rriv[e\u00e9]e[^<\d]*?(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  const depM = html.match(/[Dd][e\u00e9]part[^<\d]*?(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  if (arrM) {
    const am = getMonth(arrM[2]);
    if (am) checkIn = arrM[3] + "-" + am + "-" + arrM[1].padStart(2, "0");
  }
  if (depM) {
    const dm = getMonth(depM[2]);
    if (dm) checkOut = depM[3] + "-" + dm + "-" + depM[1].padStart(2, "0");
  }
}

// --- Extraction check-in / check-out times ---
let checkInTime = "";
let checkOutTime = "";

m = html.match(/[Aa]rriv[e\u00e9]e[^<\d]*?(\d{1,2})[h:]\s*(\d{2})?/);
if (m) checkInTime = m[1].padStart(2, "0") + ":" + (m[2] || "00");

m = html.match(/[Dd][e\u00e9]part[^<\d]*?(\d{1,2})[h:]\s*(\d{2})?/);
if (m) checkOutTime = m[1].padStart(2, "0") + ":" + (m[2] || "00");

// --- Extraction du nombre de voyageurs ---
let nbGuests = 1;
m = html.match(/(\d+)\s+voyageur/i);
if (!m) m = html.match(/(\d+)\s+guest/i);
if (!m) m = html.match(/voyageurs?\s*:\s*(\d+)/i);
if (m) nbGuests = parseInt(m[1], 10);

// --- Extraction du montant ---
let amount = null;
m = html.match(/[Tt]otal[^0-9\u20ac]*[\u20ac]?\s*([\d\s]+[.,]\d{2})\s*[\u20acEUR]?/);
if (!m) m = html.match(/[Rr]evenus?\s*:?\s*[\u20ac]?\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/[\u20acEUR]\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/([\d\s]+[.,]\d{2})\s*[\u20acEUR]/);
if (m) {
  amount = parseFloat(m[1].replace(/\s/g, "").replace(",", "."));
}

// --- Extraction de la reference Airbnb ---
let platformRefId = "";
m = html.match(/reservations\/details\/(HM[A-Z0-9]+)/);
if (!m) m = html.match(/\b(HM[A-Z0-9]{6,12})\b/);
if (!m) m = subject.match(/\b(HM[A-Z0-9]{6,12})\b/);
if (!m) m = html.match(/[Cc]ode\s+de\s+confirmation\s*:?\s*([A-Z0-9]{8,14})/);
if (!m) m = html.match(/[Cc]onfirmation\s+code\s*:?\s*([A-Z0-9]{8,14})/);
if (m) platformRefId = m[1].trim();

// --- Extraction du nom de la propriete ---
let propertyName = "";
m = subject.match(/l'annonce\s+(.+?)\s+pour\s/i);
if (!m) m = subject.match(/annonce\s+(.+?)\s+pour\s/i);
if (!m) m = subject.match(/concernant\s+(.+?)\s+pour\s/i);
if (!m) m = html.match(/votre\s+(?:logement|bien|propri[e\u00e9]t[e\u00e9]|appartement|studio|maison|annonce)\s+([^<\n"]+)/i);
if (!m) m = html.match(/[Ll]ogement\s*:\s*([^<\n]+)/);
if (m) {
  propertyName = m[1].trim().replace(/["\u00ab\u00bb]/g, "").trim();
}

// --- Construction de l'output ---
const result = {
  platform: "airbnb",
  emailType: emailType,
  guestName: guestName || "[NON DETECTE]",
  checkIn: checkIn || "[NON DETECTE]",
  checkOut: checkOut || "[NON DETECTE]",
  checkInTime: checkInTime || null,
  checkOutTime: checkOutTime || null,
  nbGuests: nbGuests,
  amount: amount,
  platformRefId: platformRefId || "[NON DETECTE]",
  propertyName: propertyName || "[NON DETECTE]",
  sourceEmailId: messageId,
  _parseQuality: {
    guestName: !!guestName,
    dates: !!(checkIn && checkOut),
    amount: amount !== null,
    reference: !!platformRefId,
    property: !!propertyName
  },
  _rawSubject: subject
};

const criticalFields = [guestName, checkIn, checkOut, platformRefId];
result._isPartialParse = criticalFields.some(f => !f);

return [{ json: result }];

// ============================================================
// WF01 — Parse Booking.com email (v2)
// Formats: confirmation, modification, annulation
// ============================================================

const html = $input.item.json.textHtml || $input.item.json.html || "";
const subject = $input.item.json.subject || "";
const messageId = $input.item.json.messageId || "";

// --- Detection du type d'email ---
let emailType = "unknown";

if (/annul/i.test(subject) || /cancel/i.test(subject)) {
  emailType = "cancellation";
} else if (/modifi/i.test(subject) || /updated/i.test(subject) || /changed/i.test(subject)) {
  emailType = "modification";
} else if (/confirm/i.test(subject) || /nouvelle?\s+r[e\u00e9]servation/i.test(subject) || /new\s+booking/i.test(subject) || /new\s+reservation/i.test(subject)) {
  emailType = "confirmation";
} else if (/renseignement/i.test(subject) || /inquiry/i.test(subject)) {
  emailType = "inquiry";
}

// --- Extraction du nom du voyageur ---
let guestName = "";
let m;

// Pattern 1: "Nom du client : Jean Dupont" (Booking FR)
m = html.match(/[Nn]om\s+(?:du\s+)?(?:client|voyageur|guest)\s*:?\s*<[^>]*>\s*([^<]+)/);
if (!m) m = html.match(/[Nn]om\s+(?:du\s+)?(?:client|voyageur|guest)\s*:?\s*([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);

// Pattern 2: "Guest name: ..."
if (!m) m = html.match(/[Gg]uest\s+name\s*:?\s*<[^>]*>\s*([^<]+)/);
if (!m) m = html.match(/[Gg]uest\s+name\s*:?\s*([A-Z][a-z]+(?:\s+[A-Z][a-z]+)*)/);

// Pattern 3: "Booked by ..." ou "Reserve par ..."
if (!m) m = html.match(/(?:[Bb]ooked\s+by|[Rr][e\u00e9]serv[e\u00e9]\s+par)\s*:?\s*([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);

// Pattern 4: dans le sujet "reservation de Jean Dupont"
if (!m) m = subject.match(/(?:de|by|from)\s+([A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+(?:\s+[A-Z\u00C0-\u00DC][a-z\u00E0-\u00FC]+)*)/);

if (m) guestName = m[1].trim();

// --- Extraction des dates ---
const moisFR = {
  "janv": "01", "janvier": "01", "jan": "01",
  "fevr": "02", "f\u00e9vr": "02", "fevrier": "02", "f\u00e9vrier": "02", "fev": "02", "feb": "02",
  "mars": "03", "mar": "03", "march": "03",
  "avr": "04", "avril": "04", "apr": "04", "april": "04",
  "mai": "05", "may": "05",
  "juin": "06", "jun": "06", "june": "06",
  "juil": "07", "juillet": "07", "jul": "07", "july": "07",
  "aout": "08", "ao\u00fbt": "08", "aug": "08", "august": "08",
  "sept": "09", "septembre": "09", "sep": "09", "september": "09",
  "oct": "10", "octobre": "10", "october": "10",
  "nov": "11", "novembre": "11", "november": "11",
  "dec": "12", "d\u00e9c": "12", "decembre": "12", "d\u00e9cembre": "12", "december": "12"
};

const moisEN = {
  "january": "01", "february": "02", "march": "03", "april": "04",
  "may": "05", "june": "06", "july": "07", "august": "08",
  "september": "09", "october": "10", "november": "11", "december": "12"
};

function getMonth(str) {
  const key = str.toLowerCase().replace(/\./g, "");
  return moisFR[key] || moisEN[key] || null;
}

let checkIn = "";
let checkOut = "";

// Pattern 1: "Check-in: 15 March 2026" / "Arrivee : 15 mars 2026" (Booking format)
const arrM = html.match(/(?:[Cc]heck[\s-]*in|[Aa]rriv[e\u00e9]e)\s*:?\s*(?:<[^>]*>\s*)*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
const depM = html.match(/(?:[Cc]heck[\s-]*out|[Dd][e\u00e9]part)\s*:?\s*(?:<[^>]*>\s*)*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);

if (arrM) {
  const am = getMonth(arrM[2]);
  if (am) checkIn = arrM[3] + "-" + am + "-" + arrM[1].padStart(2, "0");
}
if (depM) {
  const dm = getMonth(depM[2]);
  if (dm) checkOut = depM[3] + "-" + dm + "-" + depM[1].padStart(2, "0");
}

// Pattern 2: format "YYYY-MM-DD" (Booking API-style)
if (!checkIn) {
  m = html.match(/(?:[Cc]heck[\s-]*in|[Aa]rriv[e\u00e9]e)\s*:?\s*(?:<[^>]*>\s*)*(\d{4}-\d{2}-\d{2})/);
  if (m) checkIn = m[1];
}
if (!checkOut) {
  m = html.match(/(?:[Cc]heck[\s-]*out|[Dd][e\u00e9]part)\s*:?\s*(?:<[^>]*>\s*)*(\d{4}-\d{2}-\d{2})/);
  if (m) checkOut = m[1];
}

// Pattern 3: format compact "15 - 18 mars 2026"
if (!checkIn) {
  m = (subject + " " + html).match(/(\d{1,2})\s*[\u2013\u2014-]\s*(\d{1,2})\s+([\w\u00e9\u00fb\u00f4]+)\.?\s+(\d{4})/);
  if (m) {
    const month = getMonth(m[3]);
    if (month) {
      checkIn = m[4] + "-" + month + "-" + m[1].padStart(2, "0");
      checkOut = m[4] + "-" + month + "-" + m[2].padStart(2, "0");
    }
  }
}

// --- Extraction check-in / check-out times ---
let checkInTime = "";
let checkOutTime = "";

m = html.match(/(?:[Cc]heck[\s-]*in|[Aa]rriv[e\u00e9]e)[^<\d]*?(\d{1,2})[h:]\s*(\d{2})?/);
if (m) checkInTime = m[1].padStart(2, "0") + ":" + (m[2] || "00");

m = html.match(/(?:[Cc]heck[\s-]*out|[Dd][e\u00e9]part)[^<\d]*?(\d{1,2})[h:]\s*(\d{2})?/);
if (m) checkOutTime = m[1].padStart(2, "0") + ":" + (m[2] || "00");

// --- Extraction du nombre de voyageurs ---
let nbGuests = 1;
m = html.match(/(\d+)\s+(?:voyageur|guest|person|adulte|traveller)/i);
if (!m) m = html.match(/(?:voyageurs?|guests?|persons?)\s*:?\s*(\d+)/i);
if (m) nbGuests = parseInt(m[1], 10);

// --- Extraction du montant ---
let amount = null;
m = html.match(/[Tt]otal\s*(?:price|prix)?\s*:?\s*(?:<[^>]*>\s*)*[\u20ac]?\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/[Pp]rix\s*:?\s*[\u20ac]?\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/[\u20acEUR]\s*([\d\s]+[.,]\d{2})/);
if (!m) m = html.match(/([\d\s]+[.,]\d{2})\s*[\u20acEUR]/);
if (m) {
  amount = parseFloat(m[1].replace(/\s/g, "").replace(",", "."));
}

// --- Extraction de la reference Booking ---
let platformRefId = "";
m = html.match(/[Nn](?:um\u00e9ro|umero|\u00b0|o)\s*(?:de\s+)?(?:r[e\u00e9]servation|confirmation|booking)\s*:?\s*(?:<[^>]*>\s*)*(\d{6,14})/);
if (!m) m = html.match(/[Bb]ooking\s*(?:number|reference|ref)\s*:?\s*(?:<[^>]*>\s*)*(\d{6,14})/);
if (!m) m = html.match(/[Cc]onfirmation\s*(?:number|code)\s*:?\s*(?:<[^>]*>\s*)*(\d{6,14})/);
if (!m) m = subject.match(/\b(\d{8,14})\b/);
if (m) platformRefId = m[1].trim();

// --- Extraction du nom de la propriete ---
let propertyName = "";
m = html.match(/(?:votre\s+)?(?:logement|bien|propri[e\u00e9]t[e\u00e9]|h[e\u00e9]bergement|(?:your\s+)?property)\s*:?\s*(?:<[^>]*>\s*)*([^<\n"]+)/i);
if (!m) m = html.match(/[Ll]ogement\s*:\s*([^<\n]+)/);
if (!m) m = subject.match(/(?:pour|for|at)\s+(.+?)(?:\s*[\u2013\u2014-]|\s*$)/i);
if (m) {
  propertyName = m[1].trim().replace(/["\u00ab\u00bb]/g, "").trim();
}

// --- Construction de l'output ---
const result = {
  platform: "booking",
  emailType: emailType,
  guestName: guestName || "[NON DETECTE]",
  checkIn: checkIn || "[NON DETECTE]",
  checkOut: checkOut || "[NON DETECTE]",
  checkInTime: checkInTime || null,
  checkOutTime: checkOutTime || null,
  nbGuests: nbGuests,
  amount: amount,
  platformRefId: platformRefId || "[NON DETECTE]",
  propertyName: propertyName || "[NON DETECTE]",
  sourceEmailId: messageId,
  _parseQuality: {
    guestName: !!guestName,
    dates: !!(checkIn && checkOut),
    amount: amount !== null,
    reference: !!platformRefId,
    property: !!propertyName
  },
  _rawSubject: subject
};

const criticalFields = [guestName, checkIn, checkOut, platformRefId];
result._isPartialParse = criticalFields.some(f => !f);

return [{ json: result }];

// ============================================================
// WF01 — Payload Builder
// Construit le payload pour POST /api/webhooks/n8n/reservation
// + lookup property_id via Supabase
// ============================================================

const config = $('Config').item.json;
const parsed = $input.item.json;

// --- Mapping emailType → status ---
const statusMap = {
  confirmation: "confirmed",
  modification: "modified",
  cancellation: "cancelled"
};
const status = statusMap[parsed.emailType] || "confirmed";

// --- Property lookup via Supabase native node ---
let propertyId = null;
let ownerId = null;

const propertyResults = $('Supabase: Get Property by Name').all();
if (propertyResults.length > 0 && propertyResults[0].json.id) {
  propertyId = propertyResults[0].json.id;
  ownerId = propertyResults[0].json.owner_id;
}

// --- Generer idempotency key ---
const idempotencyKey = `wf01-${parsed.platform}-${parsed.platformRefId}-${parsed.emailType}-${Date.now()}`;

// --- Construire le payload ---
const payload = {
  property_id: propertyId,
  owner_id: ownerId,
  platform: parsed.platform,
  platform_ref_id: parsed.platformRefId !== "[NON DETECTE]" ? parsed.platformRefId : null,
  status: status,
  source: "email",
  guest_name: parsed.guestName !== "[NON DETECTE]" ? parsed.guestName : null,
  guest_email: null, // Non disponible par email
  nb_guests: parsed.nbGuests || 1,
  check_in: parsed.checkIn !== "[NON DETECTE]" ? parsed.checkIn : null,
  check_out: parsed.checkOut !== "[NON DETECTE]" ? parsed.checkOut : null,
  check_in_time: parsed.checkInTime || null,
  check_out_time: parsed.checkOutTime || null,
  amount: parsed.amount,
  email_message_id: parsed.sourceEmailId || null,
  raw_email_data: {
    subject: parsed._rawSubject,
    parseQuality: parsed._parseQuality,
    isPartialParse: parsed._isPartialParse
  }
};

// --- Alertes parsing partiel ---
const alerts = [];
if (parsed._isPartialParse) {
  alerts.push({
    type: "partial_parse",
    message: `Parsing partiel pour email ${parsed.platform}: champs manquants`,
    missingFields: Object.entries(parsed._parseQuality)
      .filter(([k, v]) => !v)
      .map(([k]) => k)
  });
}

if (!propertyId && parsed.propertyName !== "[NON DETECTE]") {
  alerts.push({
    type: "property_not_found",
    message: `Propriete "${parsed.propertyName}" non trouvee en base`,
    propertyName: parsed.propertyName
  });
}

return [{
  json: {
    payload: payload,
    idempotencyKey: idempotencyKey,
    alerts: alerts,
    _meta: {
      emailType: parsed.emailType,
      platform: parsed.platform,
      isNewConfirmed: parsed.emailType === "confirmation" && status === "confirmed",
      isPartialParse: parsed._isPartialParse
    }
  }
}];
